import pool from './deeptrader-backend/config/database.js';

const tables = ['users','exchange_accounts','exchange_policies','bot_instances','bot_exchange_configs'];

try {
  const meta = await pool.query('select current_database() as db, now() as now');
  console.log('platform_db', meta.rows[0]);

  for (const t of tables) {
    const reg = await pool.query("select to_regclass('public.'||$1) as r", [t]);
    const r = reg.rows[0].r;
    if (!r) {
      console.log('table', t, 'MISSING');
      continue;
    }
    const n = await pool.query(`select count(1)::bigint as n from ${t}`);
    console.log('table', t, 'rows', n.rows[0].n);
  }

  await pool.end();
  console.log('OK');
} catch (e) {
  console.error('PLATFORM_DB_PROBE_ERROR', e && e.message ? e.message : String(e));
  try { await pool.end(); } catch {}
  process.exit(1);
}
